from vex import verify, Guardrail
from agno import Agent, Memory

@verify([
    Guardrail('audit_trail', 'Creates Part 11 compliant decision log'),
    Guardrail('schema_validation', 'Validates nested medical schemas')
])
def auditable_diagnosis_chain(agent: Agent, symptoms: str, labs: dict):
    memory = Memory()

    # Session with persistent audit
    memory.add('symptoms', symptoms)
    differential = agent.run({
        'prompt': f'Differential diagnosis: {symptoms}',
        'memory': memory
    })

    validated_labs = agent.run({
        'type': 'structured',
        'schema': {
            'type': 'object',
            'properties': {
                'creatinine': {'type': 'number'},
                'hemoglobin': {'type': 'number', 'minimum': 0}
            }
        },
        'input': labs
    })

    final_dx = agent.run({
        'prompt': f'Diagnosis with labs: {validated_labs}',
        'memory': memory
    })
    return {'diagnosis': final_dx, 'audit_id': memory.session_id}

