from vex import verify, Guardrail
from agno import Agent, Team

@verify([
    Guardrail('consistency_check', 'Validates team agent alignment'),
    Guardrail('no_contradictions', 'Flags conflicting medical recommendations')
])
def coordinated_care_team():
    team = Team([
        Agent(name='Cardiology', model='gpt-4o'),
        Agent(name='Endocrinology', model='gpt-4o'),
        Agent(name='Pharmacy', model='gpt-4o')
    ])

    patient_case = {
        'ekg': 'b64_image',
        'glucose': 450,
        'meds': ['metformin']
    }

    # Parallel specialist review
    results = team.run_parallel([
        {'agent': 'Cardiology', 'input': patient_case['ekg']},
        {'agent': 'Endocrinology', 'input': patient_case},
        {'agent': 'Pharmacy', 'input': patient_case['meds']}
    ])

    consensus = team.coordinator.run({
        'prompt': f'Reconcile: {results}',
        'require_consensus': True
    })

    return consensus

# Prevents contradictory care plans
